const r = $input.first().json;

const safeInt = (v) => parseInt(v) || 0;
const safeFloat = (v) => (v != null && v !== '') ? parseFloat(v) : null;

// Revenue data
const applyFailed   = safeInt(r.apply_failed_count);
const exportedCount = safeInt(r.exported_count);
const approvedCount = safeInt(r.approved_count);
const draftCount    = safeInt(r.draft_count);
const totalGaps     = safeInt(r.total_gaps);
const totalLoss     = safeFloat(r.total_estimated_loss) || 0;
const staleObs      = safeInt(r.stale_obs);
const marketMedian  = safeFloat(r.market_median);
const topGapApt     = r.top_gap_apt;
const topGapNights  = safeInt(r.top_gap_nights);
const topGapStart   = r.top_gap_start ? String(r.top_gap_start).slice(0, 10) : null;
const topGapEnd     = r.top_gap_end   ? String(r.top_gap_end).slice(0, 10)   : null;
const topGapLoss    = safeInt(r.top_gap_loss);

// System vars from previous step
const sysVars = $('Load System Vars').all().reduce((acc, item) => {
  acc[item.json.key] = item.json.value;
  return acc;
}, {});

const ownerChatId           = sysVars['owner_chat_id'] || '';
const lastSentAt            = sysVars['revenue_notification_last_sent_at'] || '';
const lastHash              = sysVars['revenue_notification_last_hash'] || '';

const BASE_PRICE = 5500;

// Build high/medium lines
const highLines = [];
const mediumLines = [];

if (applyFailed > 0)
  highLines.push(`• ⚠️ Ошибки применения: ${applyFailed} ${applyFailed === 1 ? 'рекомендация не применена' : 'рекомендации не применены'} → проверьте audit log`);

if (exportedCount > 0)
  highLines.push(`• 📋 Готово к ручному применению: ${exportedCount} ${exportedCount === 1 ? 'цена ждёт' : 'цены ждут'} переноса в RealtyCalendar`);

if (totalGaps > 0 && totalLoss > 0) {
  let gapNote = '';
  if (topGapApt && topGapStart) {
    const startFmt = topGapStart.slice(5).replace('-', '.');
    const endFmt   = topGapEnd   ? topGapEnd.slice(5).replace('-', '.')   : '?';
    gapNote = ` (№${topGapApt}: ${topGapNights} н. ${startFmt}–${endFmt})`;
  }
  highLines.push(`• 🪟 Маленькие окна: ${totalGaps} ${totalGaps < 5 ? ['','окно','окна','окна','окна'][totalGaps] || 'окон' : 'окон'}, потеря ${Math.round(totalLoss).toLocaleString('ru-RU')} ₽${gapNote}`);
}

if (approvedCount > 0)
  mediumLines.push(`• ✅ Одобрено, но не экспортировано: ${approvedCount} ${approvedCount === 1 ? 'рекомендация' : 'рекомендации'}`);

if (draftCount > 0)
  mediumLines.push(`• 📝 Ждут решения: ${draftCount} ${draftCount === 1 ? 'рекомендация' : 'рекомендации'} (одобрить или отклонить)`);

if (staleObs > 0)
  mediumLines.push(`• 📊 Данные конкурентов устарели: ${staleObs} ${staleObs === 1 ? 'наблюдение' : 'наблюдений'} старше 14 дней`);

if (marketMedian != null && marketMedian > BASE_PRICE * 1.1) {
  const diff = Math.round(marketMedian - BASE_PRICE);
  mediumLines.push(`• 📈 Рынок выше базы: медиана ${Math.round(marketMedian).toLocaleString('ru-RU')} ₽/сут (+${diff.toLocaleString('ru-RU')} ₽)`);
}

const hasHigh   = highLines.length > 0;
const hasMedium = mediumLines.length > 0;
const hasActions = hasHigh || hasMedium;

// Build message
let text = '';
if (hasActions) {
  text += '📊 *Акваторинг Revenue: что сделать сегодня*\n\n';
  if (hasHigh) {
    text += '🔴 *Срочно:*\n' + highLines.join('\n') + '\n\n';
  }
  if (hasMedium) {
    text += '🟡 *Важно:*\n' + mediumLines.join('\n') + '\n\n';
  }
  text += '👉 https://admin.aquatoring.ru/revenue';
}

// Compute simple hash of actions (for anti-spam)
const actionKey = [...highLines, ...mediumLines].join('|');
const hashStr = Array.from(actionKey).reduce((h, c) => {
  return ((h << 5) - h + c.charCodeAt(0)) | 0;
}, 0).toString(16);

// Anti-spam check
const nowMs = Date.now();
const lastSentMs = lastSentAt ? new Date(lastSentAt).getTime() : 0;
const sameHash = hashStr === lastHash;
const within24h = (nowMs - lastSentMs) < 24 * 3600 * 1000;
const shouldSkip = !hasActions || (sameHash && within24h);

return [{
  json: {
    owner_chat_id: ownerChatId,
    message_text: text,
    message_hash: hashStr,
    has_actions: hasActions,
    has_high: hasHigh,
    has_medium: hasMedium,
    should_skip: shouldSkip,
    skip_reason: shouldSkip
      ? (!hasActions ? 'no_actions' : `same_hash_within_24h (hash=${hashStr}, sent=${lastSentAt})`)
      : 'will_send',
    last_sent_at: lastSentAt,
    last_hash: lastHash,
    // preview for logs
    high_count: highLines.length,
    medium_count: mediumLines.length
  }
}];
